// Binary to Decimal Conversion in C
#include <stdio.h>

int binaryToDecimal(long long binary) {
    int decimal = 0, base = 1, remainder;

    while (binary > 0) {
        remainder = binary % 10;
        decimal = decimal + remainder * base;
        binary = binary / 10;
        base = base * 2;
    }
    return decimal;
}

int main() {
    long long binaryNumber;
    printf("Enter binary number: ");
    scanf("%lld", &binaryNumber);
    printf("Decimal equivalent: %d\n", binaryToDecimal(binaryNumber));
    return 0;
}

// 2-to-1 Multiplexer in Verilog (Behavioral)
module mux2to1 (input a, b, select, output reg y);

    always @ (a, b, select)
    begin
        if (select == 0)
            y = a;      // When select is 0, output = a
        else
            y = b;      // When select is 1, output = b
    end

endmodule

// Testbench for simulation
module tb_mux;
    reg A, B, S;
    wire Y;

    mux2to1 M1 (A, B, S, Y);

    initial begin
        $display("A B S | Y");
        $monitor("%b %b %b | %b", A, B, S, Y);
        A=0; B=0; S=0; #10;
        A=0; B=1; S=0; #10;
        A=1; B=0; S=1; #10;
        A=1; B=1; S=1; #10;
    end
endmodule

# Boolean Function: F = A.B + A.C (using logic gates)

def NOT(a):
    return not a

def AND(a, b):
    return a and b

def OR(a, b):
    return a or b

def boolean_function(A, B, C):
    # F = A.B + A.C  (Sum of Products form)
    term1 = AND(A, B)    # A AND B
    term2 = AND(A, C)    # A AND C
    F = OR(term1, term2) # (A.B) OR (A.C)
    return F

# Generate truth table
print("A B C | F = A.B + A.C")
print("-" * 20)
for A in [0, 1]:
    for B in [0, 1]:
        for C in [0, 1]:
            F = boolean_function(A, B, C)
            print(f"{A} {B} {C} | {int(F)}")
